651:     @SuppressWarnings("unchecked")
652:     public void handleOperatorEvent(OperatorEvent event) {
653:         if (event instanceof WatermarkAlignmentEvent) {
654:             updateMaxDesiredWatermark((WatermarkAlignmentEvent) event);
655:             checkWatermarkAlignment();
656:             checkSplitWatermarkAlignment();
657:         } else if (event instanceof AddSplitEvent) {
658:             handleAddSplitsEvent(((AddSplitEvent<SplitT>) event));
659:         } else if (event instanceof SourceEventWrapper) {
660:             sourceReader.handleSourceEvents(((SourceEventWrapper) event).getSourceEvent());
661:         } else if (event instanceof NoMoreSplitsEvent) {
662:             sourceReader.notifyNoMoreSplits();
663:         } else if (event instanceof IsProcessingBacklogEvent) {
664:             if (eventTimeLogic != null) {
665:                 eventTimeLogic.emitImmediateWatermark(System.currentTimeMillis());
666:             }
667:             output.emitRecordAttributes(
668:                     new RecordAttributesBuilder(Collections.emptyList())
669:                             .setBacklog(((IsProcessingBacklogEvent) event).isProcessingBacklog())
670:                             .build());
671:         } else {
672:             throw new IllegalStateException("Received unexpected operator event " + event);
673:         }
674:     }
