676:     private void handleAddSplitsEvent(AddSplitEvent<SplitT> event) {
677:         try {
678:             List<SplitT> newSplits = event.splits(splitSerializer);
679:             if (operatingMode == OperatingMode.OUTPUT_NOT_INITIALIZED) {
680:                 // For splits arrived before the main output is initialized, store them into the
681:                 // pending list. Outputs of these splits will be created once the main output is
682:                 // ready.
683:                 splitsToInitializeOutput.addAll(newSplits);
684:             } else {
685:                 // Create output directly for new splits if the main output is already initialized.
686:                 createOutputForSplits(newSplits);
687:             }
688:             sourceReader.addSplits(newSplits);
689:             createMetricGroupForSplits(newSplits);
690:         } catch (IOException e) {
691:             throw new FlinkRuntimeException("Failed to deserialize the splits.", e);
692:         }
693:     }
